UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Conocer las capacidades corporales", "Crear un ambiente de distensión", "Fomentar el desarrollo del criterio"], "materiales": ["Sin Materiales"], "variaciones": "Si no el traslado de un participante como \"jarra\" se hace complejo y hay buen clima, se puede utilizar un recipiente con agua y sin tapa para reemplazar a la \"jarra\".", "recomendaciones": "Procure evitar que los equipos hagan un exceso de fuerza, y genere equipos equilibrados en fuerzas y peso.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraDeJarras.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es impor