UPDATE public.articulos SET metadata = '{"areas": ["corporalidad"], "lugares": ["Campo Abierto", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energías"], "materiales": ["Bolsa", "Cuerda"], "variaciones": "Una variación más sencilla puede ser sin un peso y simplemente formar el círculo con la cuerda a la misma altura del piso.", "recomendaciones": "Ponga especial atención a posibles caídas que se pueden producir por golpes con el peso en la cuerda, o con la misma cuerda que se amarre en los pies de las y los jugadores al momento de saltar.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_esquivaElTiro.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo con asombro la belleza del entorno natural y respetando la vida de plantas y animales al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, aceptando con madurez la victoria o derrota."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo para el logro de metas colectivas."}]}'::jsonb WHERE id = 'f4373764-4b71-4f03-b768-1e16316c9b13';
