UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Cinta Adhesiva", "Lápiz", "Papel"], "variaciones": "Las y los personajes pueden variar por diversas temáticas, por ejemplo, se pueden usar sólo personajes de la historia del movimiento para reforzar conocimiento sobre historia, o puede colocar nombres de canciones y para descifrar la canción le deben cantar una estrofa de la canción. O entregar la información con mímicas, etc.", "recomendaciones": "Utilice personajes conocidos para los participantes, no dificulte los personajes es una dinámica para pasar un buen rato y reforzar las relaciones entre niños, niñas y jóvenes.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DinamicaQuienCuentaMiHistoria.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para el logro de metas colectivas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no en beneficio de su comunidad."}]}'::jsonb WHERE id = '53cbdb8e-ffce-413b-bb9a-601fd070dc07';
UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Fomentar un entorno de confianza"], "materiales": ["Pañolin", "Silbato"], "variaciones": "Puede variar las indicaciones que dan los \"árboles\" para que sean determinados sonidos cuando se están acercando.", "recomendaciones": "Procure que el terreno está nivelado y libre de obstáculos que impidan un caminar seguro de los \"jardineros\".", "justificacion_areas": "Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElJardinero.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso para el éxito de la actividad."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opinión cuando estoy convencida que es correcta.", "unidad": "Compañía", "como_se_cumple": "Ejercitando la escucha activa, argumentando sus opiniones con madurez y aceptando críticas constructivas al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso para el éxito de la actividad."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que pienso con respeto hacia los demás personas.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la toma de decisiones grupales, la empatía y la autodisciplina al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso en la patrulla."}, {"id": "6c2b5054-70e8-4529-957f-a8abea073918", "area": "Afectividad", "texto": "Expreso mis opiniones libremente, sin descalificar a los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso."}, {"id": "d0ba748f-313b-4ffe-b2a3-fb21c1f8943f", "area": "Afectividad", "texto": "Practico una conducta asertiva y una actitud afectuosa hacia las demás personas, sin inhibiciones ni agresividad.", "unidad": "Clan", "como_se_cumple": "Viviendo su compromiso espiritual de forma activa y trascendente, traduciendo sus creencias en acciones de servicio al prójimo al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al guiar con la voz y sonidos a un compañero vendado para recoger objetos, evitando a los ''árboles'' que bloquean el paso para el éxito 