UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "08 participantes", "duracion": "20 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Estimular la confianza", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Puede permitir que los submarinos se hundan entre sí para evitar que lleguen a sus metas, para destruir a otro submarino puede chocarlo por un costado o hacer que se separen, también puede hacer que el primer jugador de la fila se convierta en un torpedo que se lanza con una señal determinada y si choca al otro submarino lo hunde.\r\n\r\nPuede hacer que la meta no sea un punto fijo para dificultar la llegada y que se mueva cada cierto tiempo, también puede hacer que los puntos de origen y destino de cada submarino sean diferentes y obligue a que se crucen entre equipos en el camino.", "recomendaciones": "Procure usar un terreno homogéneo y parejo para evitar accidentes por caídas.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeSubmarinos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador en un ambiente fraterno."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador con sus compañeros de seisena."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador para el logro de metas colectivas."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, aceptando con madurez la victoria o derrota."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '77f087e8-4dab-4a7b-a25d-9ca93292014d';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["compañía", "avanzada", "clan"], "objetivos": ["Estimular la participación", "Facilitar el conocimiento entre los pares"], "materiales": ["Lápiz", "Papel"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DosMentirasYUnaVerdad.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas para el logro de metas colectivas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al compartir relatos personales y agudizar la escucha para discernir afirmaciones verdaderas de falsas en beneficio de su comunidad."}]}'::jsonb WHERE id = 'b8daf1ee-84cd-46e5-a871-f6371673db05';
