UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "carácter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Fomentar la comunicación e interpretación", "Fomentar la comunicación en el grupo", "Fomentar un entorno de confianza", "Permitir el contacto físico"], "materiales": ["Pañolin"], "variaciones": "Puede hacer lo mismo con otras partes del cuerpo, como la nariz, los pies, las mejillas, etc.", "recomendaciones": "Haga las siguientes preguntas al finalizar ¿Qué sensaciones experimentaron? ¿Hubo resistencias a hacer este juego? ¿Qué tipo de reflexiones surgieron?", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ManoConMano.png", "objetivos_educativos": [{"id": "6e25f6ed-277c-41b4-9d0f-322b0a2d4c94", "area": "Afectividad", "texto": "Acepto las opiniones de mis compañeros, aunque yo piense distinto.", "unidad": "Manada", "como_se_cumple": "Colaborando fraternalmente con su seisena para apoyarse mutuamente y divertirse juntos al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "c8993915-0234-464c-934e-2a09f8c4338e", "area": "Afectividad", "texto": "Digo lo que pienso sin ofender o insultar a mis compañeros ni burlarme de ellos.", "unidad": "Manada", "como_se_cumple": "Trabajando de forma cooperativa en su seisena, valorando el esfuerzo grupal por sobre el individual al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos para el éxito de la actividad."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opinión cuando estoy convencida que es correcta.", "unidad": "Compañía", "como_se_cumple": "Ejercitando la escucha activa, argumentando sus opiniones con madurez y aceptando críticas constructivas al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos para el éxito de la actividad."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que pienso con respeto hacia los demás personas.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la toma de decisiones grupales, la empatía y la autodisciplina al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos en la patrulla."}, {"id": "6c2b5054-70e8-4529-957f-a8abea073918", "area": "Afectividad", "texto": "Expreso mis opiniones libremente, sin descalificar a los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Actuando con total honestidad y aprendiendo la importancia de decir la verdad al jugar de forma transparente y honesta al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Demostrando rectitud y asumiendo las consecuencias de sus acciones con sinceridad al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos, reforzando su honestidad personal."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos, aportando al mantenimiento de la armonía en su unidad."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "E