UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Estimular la atención a los detalles", "Trabajo en equipo"], "materiales": ["Caja", "Listado de temas", "Objetos Varios"], "variaciones": "Puede variar la actividad cambiando el tamaño de la caja o colocando varias cajas una por objeto, sin embargo, debe cerrarlas después de que cada participante las abra, o aumentar la dificultad cuando no encuentren el objeto en la caja deben volver sin nada a su equipo, hasta que encuentren el objeto que buscan.", "recomendaciones": "Procure dar dinamismo y velocidad motivando a los participantes en cada salida del punto de partida para agregar \"presión\" y forzar el error.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLaCajaSorpresa.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada, aportando al mantenimiento de la armonía en su unidad."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Actuando con total honestidad y aprendiendo la importancia de decir la verdad al jugar de forma transparente y honesta al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Demostrando rectitud y asumiendo las consecuencias de sus acciones con sinceridad al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada, reforzando su honestidad personal."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada, aportando al mantenimiento de la armonía en su unidad."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada para el logro de metas colectivas."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada en un ambiente fraterno."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada con sus compañeros de seisena."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr en relevos para extraer y adivinar mediante el tacto los objetos ocultos en una caja cerrada para el logro de metas colectivas."}]}'::jsonb WHERE id = '639da980-bb77-4e57-abf1-56bfdc64e39d';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "35 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acción", "Desarrollar la motricidad", "Estimular la creatividad", "Favorecer la comunicación en el grupo", "Trabajo en equipo"], "materiales": ["Diarios o Periódicos", "Objetos Varios", "Palos de Maqueta", "Papel", "Pegamento"], "variaciones": "Puede variar los materiales entregados para la construcción de la torre, por ejemplo, se pueden utilizar también espaguettis, cartón, etc.", "recomendaciones": "Procure hacer énfasis en la evaluación posterior a la construcción de la torre, de forma de realzar que las características individuales ayudan a mejorar el todo del equipo.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_UnaTorreAltaFirmeYHermosa.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas para el logro de metas colectivas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al diseñar y construir una torre estable utilizando únicamente materiales limitados como periódicos, fideos o bombillas en beneficio de su comunidad."}]}'::jsonb WHERE id = '334dd057-0cda-4817-b473-e45367277f73';
UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar el carácter mediante la cooperación", "Estimular la creatividad", "Trabajo en equipo"], "materiales": "", "variaciones": "Una variación posible es cambiar sólo un trozo entre cada equipo, es decir, de la fotografía A se toma un trozo y se coloca en B, de la B se toma un trozo y se coloca en C, y así según cuantas fotografías haya.\r\n\r\nCon esta variación se busca mostrar a los participantes la interdepencia que tienen los equipos unos con otros y no es sino hasta que hablan con otro equipo que podrán resolver la situación.", "recomendaciones": "Procure dejar los trozos vueltos para abajo de forma que el trozo sacado por le participante sea más sorpresivo al ubicarlo en la restauración.\r\n\r\nDeje las reglas muy claras desde un principio, al ser un juego que promueve la creatividad, es necesario establecer el marco de trabajo general.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLaFotografia.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "