UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Desfogue de Energías", "Refuerzo de habilidades físicas"], "materiales": ["Sin Materiales"], "variaciones": "Puede variar el juego manteniendo al equipo en unido, en este caso \"jinete\" y \"caballo\" llegarían hasta el extremo del campo y volverían, para hacer el relevo con la o el compañero que sigue.", "recomendaciones": "Procure que haya un equilibrio de fuerzas físicas entre los equipos y tenga criterio en los Relevos basándose en el peso de cada participante, evite accidentes por sobreesfuerzo físico.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosDelJinete.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Integrando la conservación del medio ambiente y el desarrollo sustentable como un pilar fundamental de su estilo de vida al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada en beneficio de su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '4c9ca7dc-ec5f-43bc-a0ff-54d9d498883b';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "25 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Bombillas", "Cinta Adhesiva", "Huevos", "Objetos Varios", "Papel craft", "Pañolin"], "variaciones": "Puede realizar la misma prueba arrojándole cosas pesadas al armazón, o variando la altura y materiales de construcción, lanzando el armazón contra algo, etc.", "recomendaciones": "Procure tener las condiciones adecuadas para la posterior limpieza en caso de ruptura de los huevos, idealmente la misma persona debe realizar la prueba de resistencia para evitar reclamos de intencionalidad.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ProtegeAlHuevo.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura para el logro de metas colectivas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura en beneficio de su comunidad."}]}'::jsonb WHERE id = '4f0ec9d9-8b81-47d6-9e0d-003572c0fe58';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "08 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Desfogue de Energías", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "Se puede indicar que sólo se puede avanzar con las manos, o aumentar la dificultad física indicando que no pueden tocar el suelo con nada que no sea las manos hasta llegar a la meta.", "recomendaciones": "Haga recomendaciones con ejemplos para las estrategias de avanzar, por ejemplo avanzar a la cuenta de tres del equipos, etc.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeCuncunas.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga de forma autónoma."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio corporal, la salud psicofísica y el autocontrol como parte integral de su desarrollo personal al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al desplazarse en fila coordinada en posición de cuclillas o tomados de los tobillos simulando el paso de una oruga en beneficio de su comunidad."}]}'::jsonb WHERE id = '44899c38-5ae2-4250-a6d5-955ef4158bb2';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Conocer las capacidades corporales", "Crear un ambiente de distensión", "Desarrollar la motricidad", "Estimular la creatividad"], "materiales": ["Agua", "Vasos plásticos o de papel"], "variaciones": "Una variación puede ser obligar a mantener las manos en una parte determinada.", "recomendaciones": "Procure un área de juego que sea despejada y plana para evitar accidentes. Al mismo tiempo considere que haya buen clima para hacer la actividad.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraConVasoDeAgua.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo con asombro la belleza del entorno natural y respetando la vida de plantas y animales al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, aceptando con madurez la victoria o derrota."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para el logro de metas colectivas."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para el logro de metas colectivas."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo en un ambiente fraterno."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo con sus compañeros de seisena."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = 'd48a794f-c9c5-4799-a032-3654fda48aa1';
