UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Estimular la atención a los detalles", "Estimular la creatividad", "Estimular la observación"], "materiales": ["Lápiz", "Objetos Varios", "Papel"], "variaciones": "Una variación puede ser limitar la cantidad de observaciones de los objetos, por ejemplo, cada participante sólo podrá correr a la meta de objetos 2 veces o 1 vez, etc.", "recomendaciones": "Procure que los objetos colocados en la mesa no se visualicen a la distancia del inicio.\r\n\r\nTenga precaución con el nivel del terreno para evitar caídas durante la carrera.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeObjetos.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas de forma autónoma."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al buscar y recolectar una lista de objetos específicos en la naturaleza según las pistas entregadas para el logro de metas colectivas."}]}'::jsonb WHERE id = '70755489-cdb1-4228-adaf-0e800ac81f0c';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Crear un ambiente de distensión", "Trabajo en equipo"], "materiales": ["Pelotas de ping pong", "Plato", "Vasos plásticos o de papel"], "variaciones": "Al momento del cuerpo a tierra este se puede reemplazar por uno de misma estructura pero el participante puede pasar por entremedio de las piernas de los demás.", "recomendaciones": "Se debe tener atención al lugar donde se realizará la actividad (tipo de suelo) y condiciones de este para evitar lesiones o caídas.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_RenosConHambre.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Integrando la conservación del medio ambiente y el desarrollo sustentable como un pilar fundamental de su estilo de vida al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo con asombro la belleza del entorno natural y respetando la vida de plantas y animales al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas, aceptando con madurez la victoria o derrota."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas para el logro de metas colectivas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas para el logro de metas colectivas."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas en un ambiente fraterno."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas con sus compañeros de seisena."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas en beneficio de su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr y esquivar obstáculos para recolectar comida (fichas) simulando ser renos hambrientos en parejas, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '4d1189f1-fdb8-420a-aa46-59525ec38313';
