UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "sociabilidad"], "lugares": ["Bosque", "Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía"], "objetivos": ["Desfogue de Energías", "Estimular la observación", "Perder el miedo a la oscuridad", "Reforzar el desarrollo de los sentidos"], "materiales": ["Pañolin", "Silbato"], "variaciones": "Una variación puede ser que en lugar de un sólo pitador loco, hayan varios, entonces se deben repartir cada cuanto uno u otro tocará el silbato.", "recomendaciones": "Procure elegir adecuadamente el terreno que debe ser parejo y sin piedras que puedan provocar accidentes", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_elPitadorLoco.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al localizar en la oscuridad a un animador que hace sonar un silbato intermitentemente, esquivando obstáculos."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al localizar en la oscuridad a un animador que hace sonar un silbato intermitentemente, esquivando obstáculos, aportando al mantenimiento de la armonía en su unidad."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "are