UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Desfogue de Energías", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Las variaciones se pueden hacer en el momento que la o el participante llega al punto de referencia (guiadora o dirigente) en ese lugar puede responder una pregunta, o hacer borrachitos, sapitos, ranitas, etc. pueden correr en una forma determinada y regresar de otra, etc.", "recomendaciones": "Procure hacer la actividad en un terreno plano, e idealmente suave, haga énfasis en la necesidad de una distancia segura entre una y otro participante que se encuentra en la fila para evitar que se pisen cuando pasen por encima.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CuerpoATierra.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, aceptando con madurez la victoria o derrota."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las nor