UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Exterior"], "cantidad": "08 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energías", "Estimular la capacidad de reacción"], "materiales": ["Sin Materiales"], "variaciones": "Puede variar la actividad haciendo que en lugar de que los participantes se levanten en secuencia uno tras otro, el animador sea quien siempre apunta al jugador o jugadora que hará el circuito.", "recomendaciones": "Procure hacer énfasis en el cuidado del cuerpo de sus compañeros y compañeras, haciendo que tengan una separación segura para evitar accidentes como que pisen alguna parte del cuerpo al caer de cada salto.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeSaltos.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al superar un circuito de obstáculos mediante saltos, relevos y saltos de saco o a pies juntos."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al superar un circuito de obstáculos mediante saltos, relevos y saltos de saco o a pies juntos."}, {"id": "b12da732-d736-480c-82b8-95b