UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aprendizaje por la acción", "Desarrollar la motricidad"], "materiales": ["Fósforos"], "variaciones": "Puede variar la actividad utilizando una vela que tendrá un efecto similar.", "recomendaciones": "Procure tomar todas la precauciones de seguridad posibles, primero no realice la actividad en un área boscosa, idealmente sólo realícela en un área cubierta por cemento y siempre tenga agua a la mano para evitar un incendio.\r\n\r\nHaga las indicaciones necesarias a los participantes sobre le el cuidado y los peligros del fuego.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraDeFosforos.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento de forma autónoma."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio corporal, la salud psicofísica y el autocontrol como parte integral de su desarrollo personal al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento para el logro de metas colectivas."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento para el logro de metas colectivas."}]}'::jsonb WHERE id = '25e55b5d-8f37-40af-9d43-ba0c4f3b74fd';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "espiritualidad"], "lugares": ["Exterior", "Interior"], "cantidad": "individual", "duracion": "20 minutos", "unidades": ["avanzada", "clan"], "descargas": [{"url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElEpitafio.pdf", "nombre": "Documento Adjunto - Hoja de Epitafio"}], "objetivos": ["Estimular el pensamiento crítico", "Estimular la reflexión"], "materiales": ["Lápiz", "Papel"], "variaciones": "Puede agregar una temática particular a los epitafios, por ejemplo, haciendo la pregunta ¿Qué diría su epitafio si usted fuera Bombero? o agregando cualquier otra circunstancia específica para ayudar a reflexionar sobre un trabajo en particular.", "recomendaciones": "Trate de generar o esperar a que se de el ambiente reflexivo adecuado para la actividad, esta es una actividad de introspección para jóvenes que en algunos casos puede generar sensibilidades.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Conecta a los participantes con la creación y el sentido de trascendencia espiritual de la hermandad scout.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElEpitafio.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida."}, {"id": "c165a639-f87a-4f6c-a637-69894848b507", "area": "Espiritualidad", "texto": "Respeto y cuido la naturaleza porque me siento responsable de la obra creadora de Dios.", "unidad": "Avanzada", "como_se_cumple": "Asumiendo un compromiso activo con el cuidado ecológico y la sustentabilidad al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida, promoviendo el respeto por el entorno."}, {"id": "0a9a9dac-0b1c-4f11-8600-291de10b1b95", "area": "Espiritualidad", "texto": "Busco siempre a Dios en forma personal y comunitaria, aprendiendo a reconocerlo en los hombres y en la Creación.", "unidad": "Clan", "como_se_cumple": "Integrando la conservación del medio ambiente y el desarrollo sustentable como un pilar fundamental de su estilo de vida al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida."}]}'::jsonb WHERE id = '18ae9052-19bf-48ca-89a3-c34f0081e7ca';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "05 participantes", "duracion": "15 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Crear un ambiente de distensión", "Desfogue de Energías", "Refuerzo de habilidades físicas"], "materiales": ["Sin Materiales"], "variaciones": "Se puede hacer por equipos, donde gana el equipo que conserva más esquinas cuando termina el juego, sin embargo, para ello es necesario que haya más participantes en el centro.", "recomendaciones": "Tenga cuidado de elegir un terreno nivelado y de hacer énfasis en el respeto por los demás para que no se empujen a la hora de ver quién llega primero a tomar una esquina.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_TomaUnaEsquina.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal."}, {"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '0e4290d8-a6c8-4bbb-94b6-7bee0aac8dc3';
UPDATE public.articulos SET metadata = '{"areas": ["sociabilidad"], "lugares": ["Campo delimitado", "Interior", "Sala"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Crear un ambiente de distensión", "Refuerzo de habilidades técnicas"], "materiales": ["Sin Materiales"], "variaciones": "Una variación para los más pequeños puede ser simplemente decir el número del lugar al azar, o cambiar el nombre de cada una de las esquinas por alguna actividad o historia que se haya contado antes.", "recomendaciones": "Utilice idealmente una sala de clases debido a que es más fácil para los más pequeños caminar sigilosamente, o adapte el lugar de acuerdo a las necesidades que tenga para desarrollar.", "justificacion_areas": "Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_AsesinoDeEsquinas.png", "objetivos_educativos": [{"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, aceptando con madurez la victoria o derrota."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = 'e23ded89-7293-4b7f-941b-7509b43a745f';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["manada"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Estimular la creatividad"], "materiales": ["Palo", "Porotos"], "variaciones": "Se puede variar según el terreno, hacerlo individual o por equipos.", "recomendaciones": "Permita a los participantes utilizar la imaginación en el desplazamiento del poroto.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDePorotos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina en un ambiente fraterno."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina con sus compañeros de seisena."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina, aceptando con madurez la victoria o derrota."}]}'::jsonb WHERE id = '73044568-1f54-4fa8-a79d-fe47fcd839a1';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Refuerzo de habilidades físicas", "Trabajo en equipo"], "materiales": ["Pañolin", "Tela"], "variaciones": "La carrera puede ser efectuada en parejas y haciendo relevos, de manera que cuando una pareja llega a un tramo, hay otra pareja esperando en ese punto para iniciar otro tramo y así sucesivamente hasta llegar a la meta.", "recomendaciones": "Ponga especial énfasis en que los jinetes deben ser llevados sobre la tela y en caso de que la fuerza de los \"Renos\" de su equipo haga que se levante sobre sus pies deben detenerse y esperar a que tome asiento el jinete y luego continuar desde el punto donde el jinete fue levantado.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElTrineodelViejitoPascuero.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos de forma autónoma."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, aceptando con madurez la victoria o derrota."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, sugiriendo mejoras de manera democrática y asertiva."}]}'::jsonb WHERE id = 'e779b517-778a-40e7-a4cf-4531c257de03';
