UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Trabajo en equipo"], "materiales": ["Agua", "Botella"], "variaciones": "Una variación de esta actividad se puede hacer cambiando las botella por otro recipiente, por ejemplo una cubeta, de esta forma al tener la boquilla más abierta que una botella es más probable que caiga agua en el traslado del contenedor en lugar de la transferencia del líquido.", "recomendaciones": "Procure evitar esta actividad durante el invierno para que no se mojen los participantes en un mal clima.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeBotellasConAgua.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, aportando al mantenimiento de la armonía en su unidad."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Actuando con total honestidad y aprendiendo la importancia de decir la verdad al jugar de forma transparente y honesta al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Demostrando rectitud y asumiendo las consecuencias de sus acciones con sinceridad al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, reforzando su honestidad personal."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, aportando al mantenimiento de la armonía en su unidad."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo con asombro la belleza del entorno natural y respetando la vida de plantas y animales al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, aceptando con madurez la victoria o derrota."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio para el logro de metas colectivas."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '4100fb9c-f7ef-4593-a381-3bedc7e6c48f';
UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "25 minutos", "unidades": ["compañía", "tropa"], "descargas": [{"url": "https://dl.dafont.com/dl/?f=morse", "nombre": "Fuente Morse (Dafont)"}], "objetivos": ["Aprender criptografía", "Aprendizaje por la acción", "Estimular el pensamiento lógico", "Trabajo en equipo"], "materiales": ["Lápiz", "Papel", "Pañolin"], "variaciones": "En lugar de vendarse los ojos los participantes y ser guiados a viva voz hasta los mensajes, también se puede reemplazar esto por un <a href=\"https://nuamana.cl/actividades/juegos/cuerpo-a-tierra/\" target=\"_blank\" rel=\"noopener\">cuerpo a tierra</a>, u otra carrera que los lleve desde un extremo al otro del campo.\r\n\r\nDe la misma manera se puede reemplazar el código morse por otra clave, para aumentar o disminuir la dificultad.", "recomendaciones": "Procure hacer la actividad en un lugar plano y despejados, sin riesgos de caídas por tropiezos o golpes en la cabeza por algo en altura.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_LeyConClaveMorse.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario para el éxito de la actividad."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opinión cuando estoy convencida que es correcta.", "unidad": "Compañía", "como_se_cumple": "Ejercitando la escucha activa, argumentando sus opiniones con madurez y aceptando críticas constructivas al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario para el éxito de la actividad."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que pienso con respeto hacia los demás personas.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la toma de decisiones grupales, la empatía y la autodisciplina al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario en la patrulla."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario para el logro de metas colectivas."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al descifrar los artículos de la Ley Scout transmitidos en clave morse por el equipo contrario para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "te