UPDATE public.articulos SET metadata = '{"areas": ["carácter"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Conocer a los demás", "Estimular el liderazgo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "Al momento de evaluar la justificación evalúe a cada participante en su justo merito y no permita que hayan agresiones emocionales hacia las y los participantes, idealmente base la evaluación en la calidad de la justificación y sea suave en como lo dice.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLiderazgo.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Actuando con total honestidad y aprendiendo la importancia de decir la verdad al jugar de forma transparente y honesta al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Demostrando rectitud y asumiendo las consecuencias de sus acciones con sinceridad al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas, reforzando su honestidad personal."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al asumir la dirección de un equipo en un circuito de relevos donde se deben tomar decisiones rápidas."}]}'::jsonb WHERE id = '6615c3d3-f10f-4a21-96a4-ec618483a588';
UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Desfogue de Energías", "Estimular el pensamiento lógico", "Promover la elaboración de estrategias", "Refuerzo de habilidades físicas"], "materiales": ["Silbato"], "variaciones": "Se podría hacer sin silbato, o tocando el silbato cada más o menos tiempo, pero podría resultar frustrante si no es encontrado.", "recomendaciones": "Atención a la zona que se delimita, debe ser segura pero llena de escondites. También es importante que sea amplia.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_elFugitivo.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al buscar y perseguir a un jugador fugitivo que se esconde y deja pistas en una zona boscosa o urbana."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al buscar y perseguir a un jugador fugitivo que se esconde y deja pistas en una zona boscosa o urbana, aportando al mantenimiento de la armonía en su unidad."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": 