UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Conocer las capacidades corporales", "Crear un ambiente de distensión", "Estimular la confianza", "Estimular la creatividad", "Fomentar un entorno de confianza"], "materiales": ["Sin Materiales"], "variaciones": "También se puede realizar con el escultor con los ojos vendados, para agregar dificultad.", "recomendaciones": "Procure dar indicaciones sobre el cuidado y el respeto del cuerpo de los demás.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_escultores.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas de forma autónoma."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas para el logro de metas colectivas."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas en un ambiente fraterno."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas con sus compañeros de seisena."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '67638ef0-43bf-4a38-92a5-48744d55e9c2';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Bosque", "Campo Abierto", "Exterior"], "cantidad": "08 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Perder el miedo a la oscuridad", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "Previo al juego, deje que las y los participantes revisen el terreno en el que se efectuará la actividad, esto para que reconozcan los lugares en que deben tener más cuidado con sus pisadas y evitar accidentes.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_cazadoresSabuesosVenados.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al rastrear el aroma o huellas de los ''venados'' en un juego de rol de caza en bosque."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Integrando la conservación del medio ambiente y el desarrollo sustentable como un pilar fundamental de su estilo de vida al rastrear el aroma o huellas de los ''venados'' en un juego de rol de caza en bosque."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", 