UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior", "Interior", "Sala"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Aprendizaje por la acción", "Fomentar la comunicación e interpretación", "Trabajo en equipo"], "materiales": ["Lápiz", "Papel"], "variaciones": "La variación puede ser el juego original de El teléfono, donde se transmite un mensaje verbal de oído en oído sin que escuche nadie más, y sin repetir el mensaje se transmite al siguiente participante.", "recomendaciones": "Debe reforzar adecuadamente en las conclusiones finales de la actividad, para que se entienda la idea de la actividad, donde el énfasis se encuentra en reforzar ala comunicación, tanto desde el punto de vista del emisor como del receptor.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElTel%C3%A9fono(ConDibujos).png", "objetivos_educativos": [{"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila para el logro de metas colectivas."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila en beneficio de su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al transmitir un dibujo trazando su silueta en la espalda del compañero de adelante hasta el final de la fila, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '46bba5a4-aa33-48b7-8eac-3dad9bcc00a8';
UPDATE public.articulos SET metadata = '{"areas": ["carácter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Perder el miedo a la oscuridad", "Reforzar lazos sociales", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_lasSardinas.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, aportando al mantenimiento de la armonía en su unidad."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Actuando con total honestidad y aprendiendo la importancia de decir la verdad al jugar de forma transparente y honesta al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Demostrando rectitud y asumiendo las consecuencias de sus acciones con sinceridad al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, reforzando su honestidad personal."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de su unidad al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, aportando al mantenimiento de la armonía en su unidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '21b42748-cac7-4ffc-969d-86bd56cbbc73';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "Una variación puede ser que si un equipo se llega a desarmar debe volver al punto de partida.", "recomendaciones": "Puede indicar que los elefantes emiten sonido y por lo mismo cada equipo debe hacer sonidos de elefantes mientras avanza.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeElefantes.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Asombrándose ante la obra creadora de Dios en la naturaleza y compartiendo momentos de gratitud en Manada al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Desarrollando hábitos de higiene, alimentación e hidratación saludables para proteger su bienestar corporal al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta, aceptando con madurez la victoria o derrota."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '844d5d4b-743e-4ebc-a734-5e7210a3be75';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Desfogue de Energías", "Perder el miedo a la oscuridad", "Trabajo en equipo"], "materiales": ["Agua", "Fuego", "Fósforos", "Palo"], "variaciones": "Una variación puede ser cambiar las fogatas por linternas, lámparas o velas y que deban votar el agua en un punto concreto de la base para apagar el objeto.", "recomendaciones": "Mantenga siempre una buena cantidad de agua en ambas bases, y siempre la fogata vigilada con una llama muy baja.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_protegiendoLaFogata.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno de forma autónoma."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio corporal, la salud psicofísica y el autocontrol como parte integral de su desarrollo personal al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno, aportando al mantenimiento de la armonía en su unidad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al defender la fogata de la patrulla del agua o viento utilizando pantallas humanas o materiales del entorno en beneficio de su comunidad."}]}'::jsonb WHERE id = 'e464a04f-bef4-40c3-92db-ab32ca0d772a';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "45 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Desarrollar la motricidad", "Estimular la observación", "Promover la elaboración de estrategias"], "materiales": ["Linterna"], "variaciones": "Una variación puede ser eliminar a las y los participantes cuando son descubiertos al avanzar.", "recomendaciones": "Tenga en consideración la iluminación en el lugar a la hora de jugar, prefiera un área boscosa para facilitar la huida de los prisioneros o un claro para dificultarla.\r\n\r\nHaga las recomendaciones de seguridad necesarias para que caminen con cuidado en un terreno sin iluminación.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_ElGuardiaYLosPrisioneros.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Adoptando hábitos de entrenamiento y autocuidado físico, regulando su esfuerzo aeróbico al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia de forma autónoma."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio corporal, la salud psicofísica y el autocontrol como parte integral de su desarrollo personal al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Esforzándose por superar desafíos físicos respetando su propio ritmo y evitando riesgos innecesarios al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando los valores espirituales scouts y el sentido de trascendencia en sus reflexiones personales tras al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia para el logro de metas colectivas."}]}'::jsonb WHERE id = '8a6d8a79-f3dd-402c-9d2e-10d91c8f86d9';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "05 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Desfogue de Energías", "Promover la elaboración de estrategias"], "materiales": ["Sin Materiales"], "variaciones": "Para iniciar el bulldog puede ser uno de los animadores de la actividad y este se retirara del centro del campo del juego cuando ya considere que hay suficientes \"bulldogs\".", "recomendaciones": "Sea claro y está atento a los que se salgan de los límites del campo.\r\n\r\nMucha gente siendo \"Bulldog\" puede causar accidentes, procure mantener un número razonable en el centro del campo de juego.\r\n\r\nHaga énfasis en el cuidado del cuerpo propio y de los demás, esta es una actividad muy física que puede causar accidentes cuando hay mucho entusiasmo en los participantes.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_BulldogIngles.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '227840aa-8ae7-42ea-84ae-2e9ba40106a1';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Agua", "Vasos plásticos o de papel"], "variaciones": "Puede variar la actividad traspasando el vaso por entre la piernas de las o los participantes. O si tiene pocos vasos sólo traspasando el vaso completo de un participante a otro.", "recomendaciones": "Procure utilizar una superficie que no se vuelva resbalosa con la caída de agua.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_relevosDelVaso.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Integrando la conservación del medio ambiente y el desarrollo sustentable como un pilar fundamental de su estilo de vida al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Aceptando sus capacidades y límites corporales, perfeccionando sus destrezas motrices y resistencia al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo con asombro la belleza del entorno natural y respetando la vida de plantas y animales al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, aceptando con madurez la victoria o derrota."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la confianza, el apoyo mutuo y la integración de todos los miembros de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para el logro de metas colectivas."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Consolidando su desarrollo personal, autocrítica y sentido de pertenencia comunitaria al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Promoviendo su proyecto de vida, la autogestión y el sentido del deber con los demás al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para el logro de metas colectivas."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Ejercitando sus habilidades socioemocionales de forma lúdica al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca en un ambiente fraterno."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Desarrollando su autonomía, respeto y sentido de responsabilidad al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca con sus compañeros de seisena."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Reflexionando sobre la Ley Scout, la presencia de Dios en la naturaleza y practicando la oración personal o comunitaria al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos colectivos al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca en beneficio de su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, aportando al mantenimiento de la armonía en su unidad."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando de manera alegre las reglas del juego y el juego limpio al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo y aplicando conscientemente las normas establecidas y el fair play al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, aceptando con madurez la victoria o derrota."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '2cde9fb7-221c-43ca-a7f0-a2057f4c57e1';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Aguja", "Cartulina"], "variaciones": "La actividad se puede hacer con los ojos vendados, donde para llegar a la cartulina su equipo lo debe guiar con gritos y lo mismo al regresar, en este caso las perforaciones deben ser más grandes.", "recomendaciones": "A los dos grupos, es recomendable que tengan un cuaderno y lápiz donde puedan escribir lo que hayan descifrado con el tacto.\r\n\r\nProcure que el terreno de juego sea parejo para evitar accidentes de caídas.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_adivinaLaPalabra.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando la comunicación asertiva, la síntesis de ideas y la capacidad de concertar opiniones diversas al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas para el logro de metas colectivas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo ideas con asertividad y respetando las decisiones tomadas en el consejo de patrulla al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en su patrulla de manera responsable al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas para el logro de metas colectivas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando y haciendo valer las normas de convivencia del grupo al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas, sugiriendo mejoras de manera democrática y asertiva."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas para el éxito de la actividad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas, aportando al mantenimiento de la armonía en su unidad."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando con respeto las normas de convivencia y el orden dentro de su patrulla al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas para el éxito de la actividad."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Evaluando y asumiendo con responsabilidad el valor de las normas colectivas al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas, aportando al mantenimiento de la armonía en su unidad."}]}'::jsonb WHERE id = '7bf6a7d3-21a1-40c7-83dd-53178bfdc23f';
